const r = await tools.exec_command({
  cmd: "while IFS= read -r p; do\n  base=${p:t}\n  hits=$(GIT_NO_LAZY_FETCH=1 git grep -n -I -F -- \"$base\" origin/main -- 'OpenAIDatabase/apps/memory-atlas/package.json' 'OpenAIDatabase/apps/memory-atlas/scripts/**' 'OpenAIDatabase/apps/memory-atlas/src/**' 'OpenAIDatabase/scripts/**' 'OpenAIDatabase/config/**' 'OpenAIDatabase/tests/**' 'OpenAIDatabase/.github/**' '.github/workflows/**' 'OpenAIDatabase/docs/**' 'OpenAIDatabase/*.md' 2>/dev/null || true)\n  hits=$(print -r -- \"$hits\" | awk -v self=\"$p\" 'index($0,self)==0')\n  n=$(print -r -- \"$hits\" | awk 'NF{n++}END{print n+0}')\n  first=$(print -r -- \"$hits\" | sed -n '1p')\n  print -r -- \"$n\\t$p\\t$first\"\ndone < <(jq -r '.candidates[] | select(.path|startswith(\"OpenAIDatabase/docs/reviews/\")) | .path' /tmp/openaidatabase_v121_s02_p1_07a6e50d/cleanup_candidates.json)",
  workdir: "[REDACTED_LOCAL_PATH]",
  yield_time_ms: 30000,
  max_output_tokens: 40000
});
text(r.output);

